126	      // Sword enchantment 8, damage 800 → 400 (50%) - 100 deductible = 300 payout
127	      // Cap = 2 × 1000 = 2000; remaining = 2000 - 300 = 1700
128	      expect(claim({
129	        policy: { items: [{ type: "sword", material: "steel", enchantment: 8, cursed: false }] },
130	        incident: { damages: [{ itemType: "sword", amount: 800 }] },
131	      })).toEqual({ payout: 300, remainingCap: 1700 });
132	    });
133	    it.todo("damage to dragon-material item fully reimbursed then deductible");
134	    it.todo("payout capped at 2× insurance sum");
135	    it.todo("deductible applies per damage event (multi-item damage)");
136	    it.todo("claim with item not in policy causes error");
137	    it.todo("claim with negative damage amount causes error");
