const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};
const DEDUCTIBLE = 100;
const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
const CAP_MULTIPLIER = 2;

type ClaimItem = { type: string; enchantment?: number };
type Damage = { itemType: string; amount: number };
type ClaimInput = {
  policy: { items: ClaimItem[] };
  incident: { damages: Damage[] };
};

export const claim = (input: ClaimInput): { payout: number; remainingCap: number } => {
  const damage = input.incident.damages[0];
  const item = input.policy.items.find((i) => i.type === damage.itemType)!;
  const reimbursementRate =
    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
      ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
      : 1;
  const payout = damage.amount * reimbursementRate - DEDUCTIBLE;
  const insuranceSum = input.policy.items.reduce(
    (sum, i) => sum + INSURANCE_VALUE_BY_TYPE[i.type],
    0,
  );
  const cap = CAP_MULTIPLIER * insuranceSum;
  return { payout, remainingCap: cap - payout };
};
